insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('28013', 'ha.bis', 'habis', '', '', '["Verba","Verba","Verba","Verba","Verba","Partikel","Adverbia","Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"Tidak ada yang tinggal lagi (karena sudah digunakan, dibagikan, dimakan, dan sebagainya); tidak bersisa.","contoh":[{"nomor":1,"teks":"Bahan bakar di dapur sudah habis."},{"nomor":2,"teks":"Semua barang dalam gudang itu habis terbakar."},{"nomor":3,"teks":"Persediaan air minum habis setelah acara selesai."}]},{"nomor":"2","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"Selesai.","contoh":[{"nomor":1,"teks":"Film itu sudah habis diputar."},{"nomor":2,"teks":"Pertunjukan sudah hampir habis."},{"nomor":3,"teks":"Pertemuan habis tepat pukul 10 malam."}]},{"nomor":"3","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"Tamat.","contoh":[{"nomor":1,"teks":"Bacalah buku itu sampai habis."},{"nomor":2,"teks":"Cerita itu habis dalam tiga bab."},{"nomor":3,"teks":"Novel itu habis saya baca semalam."}]},{"nomor":"4","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"Sudah sampai pada batas waktu yang ditentukan.","contoh":[{"nomor":1,"teks":"Kontraknya telah habis."},{"nomor":2,"teks":"Masa berlaku kartu ini sudah habis."},{"nomor":3,"teks":"Sewa rumahnya habis bulan lalu."}]},{"nomor":"5","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"Keluar biaya.","contoh":[{"nomor":1,"teks":"Ia habis dua juta rupiah untuk perbaikan motor."},{"nomor":2,"teks":"Untuk pergi ke tempat kerjanya, ia habis enam ribu rupiah setiap hari."},{"nomor":3,"teks":"Kami habis cukup banyak uang untuk pesta itu."}]},{"nomor":"6","kelasKata":[{"kode":"p","nama":"Partikel","tipe":"kelas_kata"}],"definisi":"Sesudah; setelah.","contoh":[{"nomor":1,"teks":"Habis makan, kami langsung pergi."},{"nomor":2,"teks":"Habis mandi dan sarapan, anak-anak berangkat ke sekolah."},{"nomor":3,"teks":"Habis belajar, mereka bermain di halaman."}]},{"nomor":"7","kelasKata":[{"kode":"adv","nama":"Adverbia","tipe":"kelas_kata"}],"definisi":"Kalau begitu (tidak begitu); maka.","contoh":[{"nomor":1,"teks":"Habis, dia yang memulai duluan."},{"nomor":2,"teks":"Habis, sampai kapan kita dapat tahan hidup begini."},{"nomor":3,"teks":"Habis, siapa lagi yang mau melakukannya?"}]},{"nomor":"8","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"Akhir.","contoh":[{"nomor":1,"teks":"Ia berjanji akan membayar utangnya habis bulan."},{"nomor":2,"teks":"Kegiatan ini habis tahun akan dievaluasi."},{"nomor":3,"teks":"Habis musim, harga akan turun."}]}]', null, '["berhabis","habis-habis","habis-habisan","kehabisan","menghabisi","menghabiskan","penghabis","penghabisan","sehabis","sehabis-habisnya","terhabiskan"]', '["habis akal","habis bulan","habis pakai","habis perkara","habis tempo"]', '[]', '["habis buah, dahan dipatah","habis dimakan api"]', '[{"peribahasa":"apa peduli kata kukuran, kerambil juga akan habis","makna":"Tidak peduli dengan perkataan orang lain, selama tujuan tetap tercapai."},{"peribahasa":"habis manis, sepah dibuang","makna":"Ungkapan yang sama dengan ''habis manis sepah dibuang'', yaitu meninggalkan atau melupakan sesuatu/seseorang setelah manfaatnya tidak ada lagi."}]');
