insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('28567', 'ha.nya', 'hanya', '', '', '["Adverbia","Adverbia","Adverbia","Adverbia","Adverbia","Adverbia"]', '[{"nomor":"1","kelasKata":[{"kode":"adv","nama":"Adverbia","tipe":"kelas_kata"}],"definisi":"cuma","contoh":[{"nomor":2,"teks":"aku -- bertanya"}]},{"nomor":"2","kelasKata":[{"kode":"adv","nama":"Adverbia","tipe":"kelas_kata"}],"definisi":"kecuali","contoh":[{"nomor":2,"teks":"semuanya mendapat hadiah, -- saya yang tidak beruntung"}]},{"nomor":"3","kelasKata":[{"kode":"adv","nama":"Adverbia","tipe":"kelas_kata"}],"definisi":"tetapi","contoh":[{"nomor":2,"teks":"kalian boleh bermain di sini, -- jangan terlalu berisik"}]},{"nomor":"4","kelasKata":[{"kode":"adv","nama":"Adverbia","tipe":"kelas_kata"}],"definisi":"tidak lebih dari","contoh":[{"nomor":2,"teks":"ia -- membawa uang receh dalam dompetnya"}]},{"nomor":"5","kelasKata":[{"kode":"adv","nama":"Adverbia","tipe":"kelas_kata"}],"definisi":"tidak lain dari","contoh":[{"nomor":2,"teks":"barang yang dibawanya pulang dari luar negeri -- sebuah kopor"}]},{"nomor":"6","kelasKata":[{"kode":"adv","nama":"Adverbia","tipe":"kelas_kata"}],"definisi":"saja (biasanya digunakan bersama “saja” untuk mengeraskan makna)","contoh":[{"nomor":2,"teks":"-- itu saja yang dapat kusumbangkan"}]}]', null, '[]', '[]', '["janganlah hanya melihat ke atas, lihatlah juga ke bawah","kain panjang hanya sehasta ditarik ke bawah tak labuh"]', '[]', '[{"peribahasa":"janganlah hanya melihat ke atas, lihatlah juga ke bawah","makna":"Agar seseorang tidak membandingkan dirinya hanya dengan orang yang lebih beruntung atau memiliki lebih banyak hal (harta, pangkat, kekuasaan). Sebaliknya, penting juga untuk melihat ke bawah, yaitu kepada orang-orang yang kurang beruntung atau berada di bawah kita. Tujuannya adalah agar kita senantiasa bersyukur atas nikmat yang telah diberikan dan tidak merasa kurang atau meremehkan apa yang sudah dimiliki."},{"peribahasa":"kain panjang hanya sehasta ditarik ke bawah tak labuh","makna":"Sesuatu itu serba tidak cukup atau tidak mencukupi untuk keperluan; menggambarkan keadaan di mana seseorang menghadapi keterbatasan atau kesulitan dalam mengatur sesuatu karena sumber daya yang sangat terbatas."}]');
