ri Ibu","hari ibun","hari jadi","hari jatuh","hari Jumat Agung","hari Jumat Besar","hari kalender","hari karier","hari kasih sayang","hari Kebangkitan Nasional","hari kejepit","hari kejepit nasional","hari kelahiran","hari kemerdekaan","hari kemudian","hari keputraan","hari Kereta Api Nasional","hari kerja","hari kiamat","hari krida","hari lahir","hari langsung","hari Lebaran","hari libur","hari libur nasional","hari lunasan","hari Mahsyar","hari matahari","hari nahar","hari nahas","hari nanti","hari Natal","hari Pahlawan","hari panen","hari pekan","hari pembalasan","hari penundaan","hari peringatan","hari potong ayam","hari raya","hari Raya Haji","hari raya Iduladha","hari raya Idulfitri","hari Raya Kurban","hari samar muka","hari Saraswati","hari sekolah","hari setelah sebar","hari setelah tanam","hari sial","hari sideris","hari sinodis","hari surya","hari takwim","hari Tani","hari tarwiah","hari tasyrik","hari trikora","hari tua","hari tunai","hari ulang tahun","hari Valentin"]', '["ada hari, ada nasi","ada hujan ada panas, ada hari boleh balas","bagai jampuk kesiangan hari","bersuluh tengah hari (lagi terang lagi bersuluh)","disangka panas sampai petang, kiranya hujan tengah hari","elok arak di hari panas","elok berarak di hari panas","emping terserak hari hujan","hari guruh takkan hujan","hari pagi dibuang-buang, hari petang dikejar-kejar","hujan panas permainan hari, senang susah permainan hidup","kucing melompat, orang terkejut dari tidurnya, ayam berkokok, hari pun siang","memasang pelita tengah hari","mujur sepanjang hari, malang sekejap mata","orang timpang jangan dicacat, ingat-ingat hari belakang","pepat kuku seperti bulan tiga hari","sabung selepas hari petang","seekor ayam tak berkokok, hari tak siangkah","siang bagai hari, terang bagai bulan","seperti buluh perindu ditiup angin tatkala dini hari"]', '[]', '[{"peribahasa":"ada hari, ada nasi","makna":"Asalkan masih hidup, tentu akan memperoleh rezeki."},{"peribahasa":"ada hujan ada panas, ada hari boleh balas","makna":"Selalu ada kesempatan untuk membalas dendam; perbuatan jahat pada akhirnya akan mendapatkan balasannya."},{"peribahasa":"bagai jampuk kesiangan hari","makna":"Kebingungan atau termenung karena kehilangan akal."},{"peribahasa":"bersuluh tengah hari (lagi terang lagi bersuluh)","makna":"Perkara yang sudah nyata (terang) atau sangat jelas dan tidak perlu dijelaskan lagi; perbuatan yang pandir/bodoh; menyia-nyiakan tenaga dan uang."},{"peribahasa":"disangka panas sampai petang, kiranya hujan tengah hari","makna":"Seseorang yang disangka akan selalu berada dalam keadaan baik atau mulia, namun tiba-tiba ditimpa kesulitan atau bahaya, sehingga jatuh melarat atau hina."},{"peribahasa":"elok arak di hari panas","makna":"Seseorang yang bersukacita karena maksud atau tujuannya telah tercapai."},{"peribahasa":"elok berarak di hari panas","makna":"Seseorang yang bersukacita atau beruntung karena maksud atau tujuannya telah tercapai."},{"peribahasa":"emping terserak hari hujan","makna":"Sangat sial atau bernasib buruk; orang yang menghadapi kesulitan untuk mengelola usahanya; sangat sial, seperti dagangan dalam jumlah banyak baru diperdagangkan, lalu pecah perang/huru-hara di negeri tersebut; orang yang penakut akan menjadi sangat berani jika ia sedang terpojok ataupun saat sedang marah."},{"peribahasa":"hari guruh takkan hujan","makna":"Orang yang terlalu marah biasanya tidak sampai memukul."},{"peribahasa":"hari pagi dibuang-buang, hari petang dikejar-kejar","makna":"Karena tidak pandai membagi waktu, selalu terburu-buru dalam melakukan suatu pekerjaan; mengejar peluang atau kesempatan baik yang pernah diabaikan sebelumnya."},{"peribahasa":"hujan panas permainan hari, senang susah permainan hidup","makna":"Dalam kehidupan manusia, sudah menjadi hal yang biasa untuk mengalami masa senang dan masa susah."},{"peribahasa":"kucing melompat, orang terkejut dari tidurnya, ayam berkokok, hari pun siang","makna":"Rasa susah atau senang orang lain dapat sampai dan berkesan pada diri kita."},{"peribahasa":"memasang pelita tengah hari","makna":"Menerangkan sesuatu perkara yang sudah jelas atau melakukan perbuatan yang sia-sia."},{"peribahasa":"mujur sepanjang hari, malang sekejap mata","makna":"Kemalangan atau kecelakaan dapat datang kapan saja, bahkan dalam waktu yang sangat singkat, meskipun seseorang telah beruntung sepanjang waktu. Oleh karena itu, peribahasa ini mengandung nasihat untuk selalu berhati-hati."},{"peribahasa":"orang timpang jangan dicacat, ingat-ingat hari belakang","makna":"Kecelakaan atau kekurangan yang menimpa seseorang janganlah terlalu dibicarakan atau dicela. Hal ini karena bisa jadi kita sendiri akan mengalami hal yang serupa di kemudian hari."},{"peribahasa":"pepat kuku seperti bulan tiga hari","makna":"Amat elok bentuk atau tokohnya."},{"peribahasa":"sabung selepas hari petang","makna":"Berserah kepada nasib (untung-untungan); usaha atau percobaan terakhir; tetap harus berusaha walaupun berkali-kali jatuh bangun di dalam suatu usaha; pertarungan akhir atau usaha yang terakhir."},{"peribahasa":"seekor ayam tak berkokok, hari tak siangkah","makna":"Bukan seorang saja yang berkuasa dan bijak dalam sesebuah negara; sesuatu pekerjaan yang dikerjakan oleh orang banyak itu tidak akan terganggu kalau hanya seorang sahaja yang tidak suka; tidak akan terjadi atau tidaknya sesuatu itu hanya karena seseorang."},{"peribahasa":"siang bagai hari, terang bagai bulan","makna":"Suatu kasus atau perkara sudah sangat jelas dan nyata; bisa merujuk pada kesalahan, kejahatan, atau maksud perkataan yang sudah tidak diragukan lagi kebenarannya."},{"peribahasa":"seperti buluh perindu ditiup angin tatkala dini hari","makna":"Suara yang sangat sedih atau suara yang lemah lembut dan merdu."}]');
