"berhati","berhati-hati","hati-hati","keberhati-hatian","keberhatian","kehati-hatian","kesehatian","memerhatikan","memperhatikan","pemerhati","pemerhatian","perhati","perhatian","sehati","seperhatian","teperhatikan"]', '["hati abu","hati kayu","hati kecil","hati kedondong","hati nurani","hati pinang","hati sanubari","hati tangan","hati tawajuh","hati terbuka","hati terlonjak","hati ungu","menyejukkan hati","permata hati"]', '["asal ada sama di hati, gajah terantai boleh dilepaskan","badan boleh dimiliki, hati tiada boleh dimiliki","bagai empedu lekat di hati","beraja di hati, bersultan di mata, (beraja di mata, bersultan di hati)","bersutan di mata beraja di hati","biar badan penat asalkan hati suka","biar badan penat, asal hati senang","buah hati cahaya mata","dalam laut boleh diajuk, dalam hati siapa tahu","diberi hati mau jantung","diuji sama merah, dalam hati (ditail) sama berat","hati (sebagai) baling-baling","hati bagai baling-baling (baling-baling di atas bukit)","hati bak sirangkak dibungkus","hati gajah sama dilapah, hati kuman (tungau) sama dicecah (dicecap)","hati gajah sama dilapah, hati tuma (tungau) sama dicecah","hati gatal, mata digaruk","hati kubang beringin gantinya","hati yang suka, peringan beban","hilang di mata, di hati jangan","ikut hati mati, ikut mata buta","ikut hati mati, ikut rasa binasa","jauh di mata, dekat di hati","jauh di mata, di hati jangan","karam di laut dapat direnangi, karam di hati bilakan sudah","karena mata buta, karena hati mati","lain di mulut, lain di hati","lain dulang lain kaki, lain orang lain hati","makan hati berulam jantung","maksud hati memeluk gunung, apa daya tangan tak sampai","mulut disuapi pisang, pantat dikait dengan onak (mulut manis hati berkait)","nafsu nafsi, raja di mata, sultan di hati","neraca palingan bungkal, hati palingan Tuhan","padang perahu di lautan, padang hati dipikirkan","padi segenggam dengan senang hati lebih baik daripada padi selumbung dengan bersusah hati","pikir itu pelita hati","rambut sama hitam, hati masing-masing","rentan hati","rupa harimau, hati tikus","segala senang hati","terbakar kampung kelihatan asap, terbakar hati siapa tahu","terkalang di mata, terasa di hati","terkilan di hati, terkalang di mata","tertambat hati, terpaut sayang","tongkat hati hubungan nyawa"]', '["beraja di hati","berbanyak hati","bercabang hati","berdetak hati","berpaling hati","hati menginjak kepala","jatuh hati","kasih bersabung dalam hati","membakar hati","membuka hati","mengukir dalam hati","menyentuh hati","senang hati","tergores dalam hati","tidak lekang dari hati"]', '[{"peribahasa":"asal ada sama di hati, gajah terantai boleh dilepaskan","makna":"Jika sudah ada persetujuan atau kesepakatan, segala halangan atau rintangan dapat diatasi."},{"peribahasa":"badan boleh dimiliki, hati tiada boleh dimiliki","makna":"Sesuatu yang tidak dapat dipaksakan atau dikuasai sepenuhnya; meskipun seseorang mungkin dapat menguasai fisik atau tindakan orang lain, perasaan, kesetiaan, dan kehendak hati seseorang tidak dapat dipaksa atau dimiliki oleh orang lain; meskipun secara fisik tunduk atau terikat, hati tetap bebas dan tidak dapat ditaklukkan."},{"peribahasa":"bagai empedu lekat di hati","makna":"Sangat karib atau sangat akrab."},{"peribahasa":"beraja di hati, bersultan di mata, (beraja di mata, bersultan di hati)","makna":"Menuruti kehendak hati atau nafsu sendiri."},{"peribahasa":"bersutan di mata beraja di hati","makna":"Menuruti kehendak hati atau nafsu sendiri."},{"peribahasa":"biar badan penat asalkan hati suka","makna":"Seseorang rela merasakan lelah atau susah payah dalam melakukan suatu pekerjaan, asalkan hati atau perasaannya bahagia dan senang dengan apa yang dikerjakannya; melakukan sesuatu dengan rela hati."},{"peribahasa":"biar badan penat, asal hati senang","makna":"Seseorang rela merasakan lelah atau susah payah dalam melakukan suatu pekerjaan, asalkan hati atau perasaannya bahagia dan senang dengan apa yang dikerjakannya; melakukan sesuatu dengan rela hati."},{"peribahasa":"buah hati cahaya mata","makna":"Anak kesayangan."},{"peribahasa":"dalam laut boleh diajuk, dalam hati siapa tahu","makna":"Apa yang tersembunyi di dalam hati atau pikiran seseorang tidak dapat kita ketahui atau duga."},{"peribahasa":"diberi hati mau jantung","makna":"Orang yang tidak tahu diri atau tidak tahu berterima kasih; sudah diberikan sesuatu, namun malah meminta lebih banyak atau sesuatu yang lebih berharga; orang yang melunjak, diberi sedikit tetapi masih meminta lebih."},{"peribahasa":"diuji sama merah, dalam hati (ditail) sama berat","makna":"Sesuatu atau seseorang sudah sepadan, seimbang, atau setara dalam status/kualitas; sudah serasi atau cocok, sering digunakan dalam konteks suami istri; seimbang atau setara dalam hal pangkat atau kedudukan; memiliki bobot yang sama atau bernilai sama ketika diuji atau ditimbang."},{"peribahasa":"hati (sebagai) baling-baling","makna":"Pendirian yang tidak tetap atau selalu berubah-ubah."},{"peribahasa":"hati bagai baling-baling (baling-baling di atas bukit)","makna":"Pendirian yang tidak tetap atau goyah; mudah berubah pikiran atau tidak memiliki keteguhan dalam pendiriannya."},{"peribahasa":"hati bak sirangkak dibungkus","makna":"Seseorang yang sangat berharap akan mendapatkan sesuatu yang diinginkannya."},{"peribahasa":"hati gajah sama dilapah, hati kuman (tungau) sama dicecah (dicecap)","makna":"Pembagian yang sama rata; jika hasilnya banyak, semua akan mendapatkan bagian yang banyak, dan jika hasilnya sedikit, semua juga akan mendapatkan bagian yang sedikit; pengagihan secara adil atau sama banyak, serta kebersamaan dalam menanggung kesenangan dan kesusahan."},{"peribahasa":"hati gajah sama dilapah, hati tuma (tungau) sama dicecah","makna":"Pembagian yang sama rata; jika hasilnya banyak, semua akan mendapatkan bagian yang banyak, dan jika hasilnya sedikit, semua juga akan mendapatkan bagian yang sedikit; pengagihan secara adil atau sama banyak, serta kebersamaan dalam menanggung kesenangan dan kesusahan."},{"peribahasa":"hati gatal, mata digaruk","makna":"Sangat ingin, tetapi tidak kuasa menyampaikan keinginannya itu; menyalahkan orang yang tidak bersalah; melakukan sesuatu yang tidak sesuai tujuan atau tidak tepat sasaran; tidak berdaya melakukan suatu hal yang ingin dikerjakan namun tidak cukup ilmu atau keterampilan; sangat ingin, tetapi tidak mempunyai syarat untuk mendapatkan keinginan tersebut."},{"peribahasa":"hati kubang beringin gantinya","makna":"Seseorang yang berhati keras atau tidak mudah terpengaruh, meskipun berada dalam keadaan yang sulit atau berbahaya; tetap teguh pendirian seperti kubangan yang tetap ada meskipun di sekitarnya telah berubah."},{"peribahasa":"hati yang suka, peringan beban","makna":"Semua pekerjaan yang dilakukan dengan kerelaan hati atau dengan senang hati, niscaya akan terasa mudah."},{"peribahasa":"hilang di mata, di hati jangan","makna":"Meskipun seseorang tidak terlihat atau berada jauh secara fisik, ia tidak boleh dilupakan dan harus tetap diingat di dalam hati."},{"peribahasa":"ikut hati mati, ikut mata buta","makna":"Orang yang hanya menuruti hawa nafsu atau keinginannya tanpa menggunakan akal sehat, pada akhirnya akan mengalami kesulitan atau kebinasaan."},{"peribahasa":"ikut hati mati, ikut rasa binasa","makna":"Orang yang hanya menuruti hawa nafsu atau keinginannya tanpa menggunakan akal pikiran akan mengalami kesulitan atau celaka pada akhirnya."},{"peribahasa":"jauh di mata, dekat di hati","makna":"Meskipun tidak bertemu karena dipisahkan oleh jarak, namun orang tersebut tetap terkenang dan teringat selalu di dalam hati."},{"peribahasa":"jauh di mata, di hati jangan","makna":"Meskipun tempat berjauhan, jangan sampai lupa-melupakan atau melupakan satu sama lain."},{"peribahasa":"karam di laut dapat direnangi, karam di hati bilakan sudah","makna":"Kesedihan karena kematian kekasih; kehilangan harta benda atau musibah di laut (karam) masih bisa diatasi atau dicari kembali, namun kesedihan mendalam akibat kehilangan orang yang dicintai (karam di hati) sangat sulit atau bahkan tidak mungkin untuk dihilangkan."},{"peribahasa":"karena mata buta, karena hati mati","makna":"Orang yang mengikuti hawa nafsu pada akhirnya akan hancur atau sengsara; badan yang menjadi celaka karena dorongan hawa nafsu yang tidak terkendali, atau menjadi binasa karena menuruti kehendak hawa nafsunya."},{"peribahasa":"lain di mulut, lain di hati","makna":"Apa yang diucapkan atau dikatakan tidak sesuai dengan apa yang sebenarnya dirasakan atau ada di dalam hati; perkataan seseorang tidak sejalan dengan isi hatinya."},{"peribahasa":"lain dulang lain kaki, lain orang lain hati","makna":"Setiap orang memiliki pendapat, kehendak, dan perasaan yang berbeda-beda; masing-masing orang memiliki kesukaannya sendiri."},{"peribahasa":"makan hati berulam jantung","makna":"Sangat bersedih hati atau bersusah hati karena perbuatan orang lain yang menyedihkan hati."},{"peribahasa":"maksud hati memeluk gunung, apa daya tangan tak sampai","makna":"Memiliki keinginan atau cita-cita yang sangat besar dan mulia, tetapi tidak memiliki kemampuan atau kesempatan untuk mencapainya."},{"peribahasa":"mulut disuapi pisang, pantat dikait dengan onak (mulut manis hati berkait)","makna":"Manis perkataannya, tetapi jahat maksudnya; bermuka-muka manis tetapi di belakang diumpat atau dibuatkan pekerjaan yang mendatangkan bahaya dan lain-lain; bujukan yang mengandung tipu muslihat."},{"peribahasa":"nafsu nafsi, raja di mata, sultan di hati","makna":"Menuruti kehendak hati sendiri atau melakukan sesuatu mengikut perhitungan sendiri tanpa mempedulikan teguran atau nasihat orang lain."},{"peribahasa":"neraca palingan bungkal, hati palingan Tuhan","makna":"Pikiran atau pendirian seseorang itu mudah berubah-ubah; meskipun timbangan (neraca) dapat dipengaruhi oleh berat (bungkal), hati manusia pada akhirnya hanya dapat diubah atau dipengaruhi oleh Tuhan."},{"peribahasa":"padang perahu di lautan, padang hati dipikirkan","makna":"Berpikir masak-masak sebelum bertindak; luasnya hati yang mampu menampung banyak pikiran; sikap tenang dalam menghadapi masalah."},{"peribahasa":"padi segenggam dengan senang hati lebih baik daripada padi selumbung dengan bersusah hati","makna":"Kesenangan hati atau ketenangan batin lebih berharga daripada kekayaan materi; lebih baik hidup sederhana dengan hati yang tenang dan tentram daripada hidup kaya raya namun dengan hati yang tidak tenang dan gelisah."},{"peribahasa":"pikir itu pelita hati","makna":"Menggunakan akal budi dan mempertimbangkan segala sesuatu dengan baik akan menjadikan seseorang lebih bijaksana; daya berpikir seseorang mampu menjadi penerang hidup; orang yang menggunakan otaknya untuk berpikir akan selalu dapat mengatasi kesulitan yang dihadapinya."},{"peribahasa":"rambut sama hitam, hati masing-masing","makna":"Setiap orang memiliki pendapat, keinginan, atau pemikiran yang berbeda-beda, meskipun secara fisik (rambut) terlihat sama."},{"peribahasa":"rentan hati","makna":"Lekas marah atau mudah tersinggung/sakit hati."},{"peribahasa":"rupa harimau, hati tikus","makna":"Penampilan luarnya tampak gagah, berani, atau menakutkan, tetapi hatinya pengecut atau penakut."},{"peribahasa":"segala senang hati","makna":"Perihal orang yang hidupnya miskin dan menderita."},{"peribahasa":"terbakar kampung kelihatan asap, terbakar hati siapa tahu","makna":"Kesusahan atau penderitaan seseorang jarang diketahui atau dipedulikan oleh orang lain, karena hal tersebut tidak terlihat secara fisik."},{"peribahasa":"terkalang di mata, terasa di hati","makna":"Ada sesuatu yang ingin dikemukakan atau disampaikan, tetapi belum terkatakan atau sulit untuk diungkapkan; tidak mampu merangkai kata-kata yang ingin dikatakan yang dapat terkenang di dalam hati."},{"peribahasa":"terkilan di hati, terkalang di mata","makna":"Terasa (terbayang) dalam hati dan sulit dihilangkan."},{"peribahasa":"tertambat hati, terpaut sayang","makna":"Seseorang yang telah jatuh cinta atau kasihan."},{"peribahasa":"tongkat hati hubungan nyawa","makna":"Seorang ibu yang sangat mengasihi anaknya."}]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('29008', 'ha.tif', 'hatif', '', '', '["Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"suara yang terdengar tanpa terlihat orangnya; suara dari langit; suara gaib","contoh":[]}]', '{"text":"[Arab هَاتِفٌ hātif n sg m ''suara tanpa rupa'']","languages":["Arab"]}', '[]', '[]', '[]', '[]', '[]');
