insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('29514', 'hi.dup', 'hidup', '', '', '["Verba","Verba","Verba","Verba","Verba","Verba","Verba","Verba","Verba","Verba","Verba","Verba","Verba"]', '[{"nomor":"1","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"masih terus ada, bergerak, dan bekerja sebagaimana mestinya (tentang manusia, binatang, tumbuhan, dan sebagainya)","contoh":[{"nomor":2,"teks":"kakeknya masih --, tetapi neneknya telah lama meninggal"}]},{"nomor":"2","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"bertempat tinggal (diam)","contoh":[{"nomor":2,"teks":"-- di desa lebih tenang daripada di kota besar"}]},{"nomor":"3","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"mengalami kehidupan dalam keadaan atau dengan cara tertentu","contoh":[{"nomor":2,"teks":"dulu dia -- mewah, sekarang merana"}]},{"nomor":"4","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"beroleh (mendapat) rezeki dengan jalan sesuatu","contoh":[{"nomor":2,"teks":"penduduk di sekitar pelabuhan itu -- dari berniaga"}]},{"nomor":"5","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"berlangsung (ada) karena sesuatu","contoh":[{"nomor":2,"teks":"yayasan itu dapat -- karena uang sumbangan para dermawan"}]},{"nomor":"6","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"tetap ada (tidak hilang)","contoh":[{"nomor":2,"teks":"peristiwa indah itu masih -- dalam ingatannya"}]},{"nomor":"7","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"masih berjalan (tentang perusahaan, perkumpulan, dan sebagainya)","contoh":[{"nomor":2,"teks":"walaupun jumlah anggotanya tidak lagi sebanyak dahulu, perkumpulan itu tetap -- juga"}]},{"nomor":"8","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"tetap menyala; tetap bergerak terus (tentang lampu, radio, api)","contoh":[{"nomor":2,"teks":"dia sudah tertidur, tetapi lampu di sampingnya masih saja --"},{"nomor":4,"teks":"arloji saya masih -- juga walaupun jatuh ke lantai"}]},{"nomor":"9","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"masih tetap dipakai (tentang bahasa, adat, sumur, dan sebagainya)","contoh":[{"nomor":2,"teks":"adat itu masih tetap -- dalam masyarakat"}]},{"nomor":"10","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"ramai (tidak sepi dan sebagainya)","contoh":[{"nomor":2,"teks":"menjelang Lebaran perdagangan kain dan makanan -- sekali"}]},{"nomor":"11","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"seakan-akan bernyawa atau benar-benar tampak seperti keadaan sesungguhnya (tentang lukisan, gambar)","contoh":[{"nomor":2,"teks":"lukisan itu sangat --"}]},{"nomor":"12","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"seperti sungguh-sungguh terjadi atau dialami (tentang cerita)","contoh":[{"nomor":2,"teks":"cerita dan gaya bahasanya segar lagi --"}]},{"nomor":"13","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"seruan yang menyatakan harapan mudah-mudahan tetap selamat","contoh":[]}]', null, '["berkehidupan","hidup-hidup","hidupan","kehidupan","memperhidup","menghidupi","menghidupkan","penghidupan","sehidup","terhidupi"]', '["hidup api","hidup tertopang"]', '["adat hidup tolong-menolong, syariat palu-memalu","bagai kerakap tumbuh di (di atas) batu, hidup enggan mati tak mau","banyak menelan garam hidup","daripada hidup bercermin bangkai, lebih baik mati berkalang tanah","daripada hidup bercermin bangkai, lebih baik mati berkalang tanah (daripada hidup berlumur tahi, lebih baik mati bertimbun bunga)","hidup bagai bayam bertabur","hidup berakal, mati beriman","hidup bertimba uang","hidup di ujung gurung orang","hidup dikandung adat, mati dikandung bumi","hidup dikandung adat, mati dikandung tanah","hidup dua muara","hidup kayu berbuah, hidup manusia biar berjasa","hidup sandar-menyandar umpama aur dengan tebing","hidup segan mati tak mau","hidup segan, mati tak embuh","hidup segan, mati tak hendak","hidup seperti musang","hidup tidak karena doa, mati tidak karena sumpah","hujan panas permainan hari, senang susah permainan hidup","jauh berjalan banyak dilihat, lama hidup banyak dirasa","jika tiada tersapu arang di muka, baiklah mati daripada hidup","kalau ada beremas hidup, tiada beremas mati","kalau bangkai galikan kuburnya, kalau hidup sediakan buaiannya","lebih baik mati berdiri daripada hidup berlutut","lebih baik mati berkalang tanah daripada hidup bercermin bangkai","mendukung biawak hidup","pengganti hidup berkeredaan, pengganti mati berkebulatan","sebaik-baiknya hidup teraniaya","selompat hidup, selompat mati","seperti kambing dikupas hidup-hidup"]', '["hidup di bawah bendera negara lain","hidup di perawanan","mengarungi hidup baru"]', '[{"peribahasa":"adat hidup tolong-menolong, syariat palu-memalu","makna":"Dalam kehidupan bermasyarakat, sudah menjadi adat untuk saling membantu, namun jika ada yang melanggar aturan atau syariat, ia harus dihukum."},{"peribahasa":"bagai kerakap tumbuh di (di atas) batu, hidup enggan mati tak mau","makna":"Hidup dalam kemelaratan dan penderitaan yang berkepanjangan; seseorang yang hidupnya sangat sulit, tetapi tidak juga meninggal."},{"peribahasa":"banyak menelan garam hidup","makna":"Telah banyak pengalaman hidup (baik suka maupun duka)."},{"peribahasa":"daripada hidup bercermin bangkai, lebih baik mati berkalang tanah","makna":"Daripada hidup menanggung malu, lebih baik mati."},{"peribahasa":"daripada hidup bercermin bangkai, lebih baik mati berkalang tanah (daripada hidup berlumur tahi, lebih baik mati bertimbun bunga)","makna":"Daripada hidup menanggung malu, lebih baik mati."},{"peribahasa":"hidup bagai bayam bertabur","makna":"Kehidupan yang serba berkecukupan dan makmur."},{"peribahasa":"hidup berakal, mati beriman","makna":"Selama hidup, hendaklah menggunakan akal budi untuk kebaikan, dan ketika meninggal dunia, hendaklah dalam keadaan beriman kepada Tuhan."},{"peribahasa":"hidup bertimba uang","makna":"Hidup dalam kemewahan dan kekayaan yang berlimpah."},{"peribahasa":"hidup di ujung gurung orang","makna":"Orang yang hidupnya bergantung pada belas kasihan orang lain."},{"peribahasa":"hidup dikandung adat, mati dikandung bumi","makna":"Selama hidup di dunia, manusia terikat oleh adat istiadat, dan setelah mati akan kembali ke tanah."},{"peribahasa":"hidup dikandung adat, mati dikandung tanah","makna":"Selama hidup di dunia, manusia terikat oleh adat istiadat, dan setelah mati akan kembali ke tanah."},{"peribahasa":"hidup dua muara","makna":"Orang yang memiliki dua sumber penghasilan atau mata pencaharian."},{"peribahasa":"hidup kayu berbuah, hidup manusia biar berjasa","makna":"Dalam hidup, hendaknya berbuat baik dan memberikan manfaat bagi orang lain."},{"peribahasa":"hidup sandar-menyandar umpama aur dengan tebing","makna":"Orang yang hidupnya saling bergantung dan tolong-menolong satu sama lain."},{"peribahasa":"hidup segan mati tak mau","makna":"Hidup dalam keadaan yang serba sulit dan menderita, tetapi tidak juga meninggal dunia."},{"peribahasa":"hidup segan, mati tak embuh","makna":"Hidup dalam keadaan yang serba sulit dan menderita, tetapi tidak juga meninggal dunia."},{"peribahasa":"hidup segan, mati tak hendak","makna":"Hidup dalam keadaan yang serba sulit dan menderita, tetapi tidak juga meninggal dunia."},{"peribahasa":"hidup seperti musang","makna":"Hidup yang selalu waspada dan berhati-hati karena merasa terancam."},{"peribahasa":"hidup tidak karena doa, mati tidak karena sumpah","makna":"Segala sesuatu dalam kehidupan, termasuk hidup dan mati, adalah kehendak Tuhan, bukan karena ucapan atau keinginan manusia."},{"peribahasa":"hujan panas permainan hari, senang susah permainan hidup","makna":"Dalam kehidupan, kesenangan dan kesusahan silih berganti, seperti halnya cuaca yang bisa berubah-ubah."},{"peribahasa":"jauh berjalan banyak dilihat, lama hidup banyak dirasa","makna":"Orang yang banyak merantau atau bepergian akan memiliki banyak pengalaman dan pengetahuan."},{"peribahasa":"jika tiada tersapu arang di muka, baiklah mati daripada hidup","makna":"Daripada hidup menanggung malu, lebih baik mati."},{"peribahasa":"kalau ada beremas hidup, tiada beremas mati","makna":"Selama masih hidup, kita masih bisa mencari harta atau kekayaan, tetapi jika sudah mati, harta tidak akan dibawa."},{"peribahasa":"kalau bangkai galikan kuburnya, kalau hidup sediakan buaiannya","makna":"Jika seseorang berbuat salah, ia harus menanggung akibatnya, tetapi jika ia berbuat baik, ia patut dihargai."},{"peribahasa":"lebih baik mati berdiri daripada hidup berlutut","makna":"Lebih baik mati dalam mempertahankan prinsip dan kehormatan daripada hidup dalam kehinaan dan penindasan."},{"peribahasa":"lebih baik mati berkalang tanah daripada hidup bercermin bangkai","makna":"Daripada hidup menanggung malu, lebih baik mati."},{"peribahasa":"mendukung biawak hidup","makna":"Menolong atau memelihara orang yang pada akhirnya akan menyusahkan atau merugikan diri sendiri."},{"peribahasa":"pengganti hidup berkeredaan, pengganti mati berkebulatan","makna":"Jika ada sesuatu yang hilang atau rusak, harus ada penggantinya yang sepadan."},{"peribahasa":"sebaik-baiknya hidup teraniaya","makna":"Meskipun hidup dalam penderitaan, tetaplah berbuat baik dan sabar."},{"peribahasa":"selompat hidup, selompat mati","makna":"Melakukan pekerjaan yang sangat berbahaya atau penuh risiko."},{"peribahasa":"seperti kambing dikupas hidup-hidup","makna":"Mengalami penderitaan atau siksaan yang sangat berat."}]');
