insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('29603', 'hi.lang', 'hilang', '', '', '["Verba","Verba","Verba","Verba","Verba"]', '[{"nomor":"1","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"lenyap; tidak ada lagi; tidak kelihatan","contoh":[{"nomor":2,"teks":"tiba-tiba benda itu -- dari pandangannya"}]},{"nomor":"2","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"tidak ada lagi perasaan (seperti marah, jengkel, suka, duka), kepercayaan, pertimbangan, dan sebagainya","contoh":[{"nomor":2,"teks":"kepercayaan kepada orang yang setiap kali ingkar janji itu telah --"}]},{"nomor":"3","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"tidak dikenang lagi; tidak diingat lagi; lenyap","contoh":[{"nomor":2,"teks":"ketenarannya -- begitu saja karena kejadian itu"}]},{"nomor":"4","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"tidak ada, tidak kedengaran lagi (tentang suara, bunyi, dan sebagainya)","contoh":[{"nomor":2,"teks":"suara yang memanggil-manggil itu makin -- dari pendengaran"}]},{"nomor":"5","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"meninggal","contoh":[{"nomor":2,"teks":"ayahnya -- beberapa bulan yang lalu"}]}]', null, '["hilang-hilang","kehilangan","menghilang","menghilangkan","penghilang","penghilangan","terhilangkan"]', '["hilang akal","hilang arah","hilang arwah","hilang bicara","hilang cahaya","hilang dalam tugas","hilang dara","hilang dari mata","hilang gaib","hilang harapan","hilang hayat","hilang ingatan","hilang kata","hilang kendali","hilang kesadaran","hilang kikis","hilang kontak","hilang lenyap","hilang malu","hilang nyawa","hilang pijar","hilang pikiran","hilang pintang","hilang redam","hilang semangat","nafsu makan"]', '["adapun manikam itu jika dijatuhkan ke dalam limbahan sekalipun, niscaya tidak hilang cahayanya","antan patah, lesung hilang","bagai kinantan hilang taji","berani hilang tak hilang, berani mati tak mati","bersarak serasa hilang, bercerai serasa mati","didenda dengan emas yang habis, dipancung dengan pedang yang hilang","esa hilang, dua terbilang","hanyut dipintasi, lulus diselami, hilang dicari","hilang (kepala) kura-kura ditelan dadanya","hilang bini boleh dicari, hilang budi badan celaka","hilang di mata, di hati jangan","hilang dicari, terapung direnangi, terbenam diselami","hilang geli karena gelitik","hilang ikan dalam kerabu","hilang jasa beliung, timbul jasa rimbas","hilang kabus, teduh hujan","hilang kilat dalam kilau","hilang pelanduk berganti kijang emas","hilang penjahit bekerbau-kerbau","hilang rona karena penyakit, hilang bangsa tidak beruang","hilang satu, sepuluh gantinya","hilang sepuh, tampak senam","hilang tak bercari, lulus tak berselami","hilang tak tentu rimbanya, mati tak tentu kuburnya","hilang tapak tukul, timbul tapak canai","hilang tentu rimbanya, mati tentu kuburnya","hilang tukul, hilanglah pahat","hilang warna karena penyakit, hilang bangsa karena tak berharta dan emas","kurang taksir, hilang laba","lulus tidak berselam, hilang tidak bercari","malang celaka Raja Genggang, anak terbeli tunjang hilang","memakan habis-habisan, menyuruh hilang-hilang","menyuruk hilang-hilang, memakan habis-habis","patah tumbuh, hilang berganti","silap bercakap terkena radak hilang jiwa percuma saja","tak akan (takkan) lari gunung dikejar, hilang kabut tampaklah dia","tak kan lari gunung dikejar, hilang kabut tampaklah dia","tuak terbeli, tunjang hilang","tunggang hilang berani mati"]', '[]', '[{"peribahasa":"adapun manikam itu jika dijatuhkan ke dalam limbahan sekalipun, niscaya tidak hilang cahayanya","makna":"Orang yang baik budi pekertinya, ke mana pun ia pergi akan tetap dihormati dan dihargai."},{"peribahasa":"antan patah, lesung hilang","makna":"Tertimpa musibah atau kemalangan secara beruntun."},{"peribahasa":"bagai kinantan hilang taji","makna":"Orang yang kehilangan kekuasaan atau wibawanya."},{"peribahasa":"berani hilang tak hilang, berani mati tak mati","makna":"Orang yang nekat atau terlalu berani dalam melakukan sesuatu yang berbahaya."},{"peribahasa":"bersarak serasa hilang, bercerai serasa mati","makna":"Perasaan sedih yang mendalam karena perpisahan dengan orang yang sangat dicintai."},{"peribahasa":"didenda dengan emas yang habis, dipancung dengan pedang yang hilang","makna":"Hukuman atau denda yang sangat berat dan tidak mungkin untuk dipenuhi."},{"peribahasa":"esa hilang, dua terbilang","makna":"Terus berjuang dan tidak menyerah meskipun mengalami kegagalan atau kehilangan; jika satu usaha gagal, masih ada usaha lain yang bisa dicoba."},{"peribahasa":"hanyut dipintasi, lulus diselami, hilang dicari","makna":"Menunjukkan sikap setia kawan dan saling membantu dalam menghadapi kesulitan."},{"peribahasa":"hilang (kepala) kura-kura ditelan dadanya","makna":"Orang yang tidak dapat menyembunyikan kesalahannya karena sudah terbukti dengan jelas."},{"peribahasa":"hilang bini boleh dicari, hilang budi badan celaka","makna":"Kehilangan harta benda masih bisa dicari gantinya, tetapi kehilangan akal sehat atau budi pekerti yang baik akan membawa celaka."},{"peribahasa":"hilang di mata, di hati jangan","makna":"Meskipun tidak bertemu atau berdekatan, jangan sampai melupakan orang yang dikasihi."},{"peribahasa":"hilang dicari, terapung direnangi, terbenam diselami","makna":"Menunjukkan sikap setia kawan dan saling membantu dalam menghadapi kesulitan."},{"peribahasa":"hilang geli karena gelitik","makna":"Kesenangan atau kegembiraan yang hilang karena sesuatu yang berlebihan atau tidak pada tempatnya."},{"peribahasa":"hilang ikan dalam kerabu","makna":"Sesuatu yang hilang atau lenyap tanpa bekas."},{"peribahasa":"hilang jasa beliung, timbul jasa rimbas","makna":"Jasa atau kebaikan seseorang yang dilupakan karena adanya jasa orang lain yang lebih baru atau lebih besar."},{"peribahasa":"hilang kabus, teduh hujan","makna":"Setelah kesulitan atau kesusahan berlalu, datanglah ketenangan dan kebahagiaan."},{"peribahasa":"hilang kilat dalam kilau","makna":"Kebaikan atau kelebihan seseorang yang tidak terlihat karena tertutup oleh kelebihan orang lain yang lebih menonjol."},{"peribahasa":"hilang pelanduk berganti kijang emas","makna":"Kehilangan sesuatu yang kurang berharga, tetapi mendapatkan ganti yang lebih baik atau lebih berharga."},{"peribahasa":"hilang penjahit bekerbau-kerbau","makna":"Kehilangan sesuatu yang kecil, tetapi harus menanggung kerugian yang lebih besar."},{"peribahasa":"hilang rona karena penyakit, hilang bangsa tidak beruang","makna":"Kehormatan atau martabat seseorang akan hilang jika ia tidak memiliki harta atau kekayaan."},{"peribahasa":"hilang satu, sepuluh gantinya","makna":"Jangan terlalu bersedih karena kehilangan sesuatu, karena akan ada gantinya yang lebih banyak atau lebih baik."},{"peribahasa":"hilang sepuh, tampak senam","makna":"Terbongkarnya sifat atau keadaan yang sebenarnya setelah hilang penampilan luarnya."},{"peribahasa":"hilang tak bercari, lulus tak berselami","makna":"Orang yang tidak dipedulikan atau tidak dihiraukan sama sekali."},{"peribahasa":"hilang tak tentu rimbanya, mati tak tentu kuburnya","makna":"Hilang tanpa jejak dan tidak diketahui nasibnya."},{"peribahasa":"hilang tapak tukul, timbul tapak canai","makna":"Sesuatu yang lama telah hilang dan digantikan oleh yang baru."},{"peribahasa":"hilang tentu rimbanya, mati tentu kuburnya","makna":"Segala sesuatu ada kepastiannya; jika seseorang hilang, pasti ada jejaknya, dan jika mati, pasti ada kuburnya."},{"peribahasa":"hilang tukul, hilanglah pahat","makna":"Jika pemimpin atau orang yang menjadi andalan telah tiada, maka bawahannya akan kehilangan arah atau pedoman."},{"peribahasa":"hilang warna karena penyakit, hilang bangsa karena tak berharta dan emas","makna":"Kehormatan atau martabat seseorang akan hilang jika ia tidak memiliki harta atau kekayaan."},{"peribahasa":"kurang taksir, hilang laba","makna":"Kesalahan dalam perhitungan atau perkiraan dapat menyebabkan kerugian."},{"peribahasa":"lulus tidak berselam, hilang tidak bercari","makna":"Orang yang tidak dipedulikan atau tidak dihiraukan sama sekali."},{"peribahasa":"malang celaka Raja Genggang, anak terbeli tunjang hilang","makna":"Nasib yang sangat sial atau malang."},{"peribahasa":"memakan habis-habisan, menyuruh hilang-hilang","makna":"Orang yang hanya mau enaknya saja, tetapi tidak mau bertanggung jawab atau menanggung susah."},{"peribahasa":"menyuruk hilang-hilang, memakan habis-habis","makna":"Orang yang pandai menyimpan rahasia atau menyembunyikan perbuatannya yang tidak baik."},{"peribahasa":"patah tumbuh, hilang berganti","makna":"Sesuatu yang hilang atau rusak akan ada gantinya yang baru; generasi yang lama akan digantikan oleh generasi yang baru."},{"peribahasa":"silap bercakap terkena radak hilang jiwa percuma saja","makna":"Kesalahan dalam berbicara dapat membawa akibat yang fatal atau membahayakan diri sendiri."},{"peribahasa":"tak akan (takkan) lari gunung dikejar, hilang kabut tampaklah dia","makna":"Tidak perlu tergesa-gesa dalam mengerjakan sesuatu, karena jika sudah waktunya, pasti akan tercapai juga."},{"peribahasa":"tak kan lari gunung dikejar, hilang kabut tampaklah dia","makna":"Tidak perlu tergesa-gesa dalam mengerjakan sesuatu, karena jika sudah waktunya, pasti akan tercapai juga."},{"peribahasa":"tuak terbeli, tunjang hilang","makna":"Mengalami kerugian atau kemalangan karena perbuatan sendiri."},{"peribahasa":"tunggang hilang berani mati","makna":"Orang yang sangat nekat dan tidak takut mati."}]');
