insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('29640', 'hi.lir', 'hilir', '', '', '["Nomina","Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"bagian sungai sebelah muara","contoh":[{"nomor":2,"teks":"sampai ke -- sungai"}]},{"nomor":"2","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"daerah sepanjang bagian muara sungai (daerah pesisir)","contoh":[{"nomor":2,"teks":"orang --"}]}]', null, '["berhilir","berhiliran","menghilir","menghiliri","menghilirkan","penghiliran","sehilir","terhilir"]', '["hilir angin","hilir malam","hilir mudik","hilir sungai"]', '["belum tentu hilir mudiknya","bergalah hilir tertawa buaya, bersuluh di bulan terang tertawa harimau","berkata di bawah-bawah mandi di hilir-hilir","berkayuh sambil ke hilir","hilir malam mudik tak singgah, daun nipah dikatakan daun abu","ikan di hulu, tuba di hilir","ke hulu kena bubu, ke hilir kena tengkalak","ke hulu menongkah surut, ke hilir menongkah pasang","ke mudik tentu hulunya, ke hilir tentu muaranya","kundur tiada menjalar ke hulu, labu tiada menjalar ke hilir","lebih baik menyesal di hulu riam, daripada menyesal di hilir riam","menangis daun bangun-bangun hendak sama dengan hilir air","mudik menyongsong arus, hilir menyongsong pasang","sambil berdendang biduk hilir","selama gagak hitam, selama air hilir","seorang ke hilir, seorang ke mudik","seperti biduk dikayuh hilir","sudah terlalu hilir malam, apa hendak dikata lagi","tak tentu hilir mudiknya","tak terkayuhkan lagi biduk hilir","tingkalak menghadap mudik, lukah menghadap hilir"]', '[]', '[{"peribahasa":"belum tentu hilir mudiknya","makna":"Belum jelas atau belum pasti keputusannya; belum diketahui bagaimana akhirnya suatu perkara."},{"peribahasa":"bergalah hilir tertawa buaya, bersuluh di bulan terang tertawa harimau","makna":"Melakukan pekerjaan yang sia-sia atau berbahaya."},{"peribahasa":"berkata di bawah-bawah mandi di hilir-hilir","makna":"Orang yang rendah hati dan tidak sombong."},{"peribahasa":"berkayuh sambil ke hilir","makna":"Melakukan dua pekerjaan sekaligus; sambil menyelam minum air."},{"peribahasa":"hilir malam mudik tak singgah, daun nipah dikatakan daun abu","makna":"Orang yang sangat sibuk sehingga tidak punya waktu untuk singgah atau beristirahat."},{"peribahasa":"ikan di hulu, tuba di hilir","makna":"Perbuatan yang sia-sia atau tidak akan berhasil."},{"peribahasa":"ke hulu kena bubu, ke hilir kena tengkalak","makna":"Tidak ada jalan keluar; serba salah."},{"peribahasa":"ke hulu menongkah surut, ke hilir menongkah pasang","makna":"Selalu mengalami kesulitan atau rintangan."},{"peribahasa":"ke mudik tentu hulunya, ke hilir tentu muaranya","makna":"Segala sesuatu ada asal-usulnya atau sumbernya."},{"peribahasa":"kundur tiada menjalar ke hulu, labu tiada menjalar ke hilir","makna":"Tabiat atau sifat seseorang tidak akan berubah."},{"peribahasa":"lebih baik menyesal di hulu riam, daripada menyesal di hilir riam","makna":"Lebih baik berpikir masak-masak sebelum bertindak daripada menyesal kemudian."},{"peribahasa":"menangis daun bangun-bangun hendak sama dengan hilir air","makna":"Mengharapkan sesuatu yang tidak mungkin terjadi."},{"peribahasa":"mudik menyongsong arus, hilir menyongsong pasang","makna":"Selalu mengalami kesulitan atau rintangan."},{"peribahasa":"sambil berdendang biduk hilir","makna":"Melakukan dua pekerjaan sekaligus; sambil menyelam minum air."},{"peribahasa":"selama gagak hitam, selama air hilir","makna":"Selama-lamanya; untuk waktu yang tidak terbatas."},{"peribahasa":"seorang ke hilir, seorang ke mudik","makna":"Tidak sependapat; berlainan arah atau tujuan."},{"peribahasa":"seperti biduk dikayuh hilir","makna":"Sangat cepat (tentang perahu atau pekerjaan)."},{"peribahasa":"sudah terlalu hilir malam, apa hendak dikata lagi","makna":"Sudah terlanjur; tidak ada gunanya lagi disesali."},{"peribahasa":"tak tentu hilir mudiknya","makna":"Tidak jelas atau tidak pasti keputusannya; belum diketahui bagaimana akhirnya suatu perkara."},{"peribahasa":"tak terkayuhkan lagi biduk hilir","makna":"Sudah tidak sanggup lagi melanjutkan usaha atau pekerjaan."},{"peribahasa":"tingkalak menghadap mudik, lukah menghadap hilir","makna":"Perangkap atau jebakan yang dipasang dengan baik sehingga mangsa tidak dapat lolos."}]');
