insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('29905', 'hi.tam', 'hitam', '', '', '["Nomina","Adjektiva"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"warna dasar yang serupa dengan warna arang","contoh":[]},{"nomor":"2","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"mengandung atau memperlihatkan warna yang serupa dengan arang","contoh":[]}]', null, '["kehitam-hitaman","kehitaman","menghitam","menghitami","menghitamkan","penghitam","penghitaman"]', '["hitam anilina","hitam antimon","hitam arang","hitam asetilena","hitam berkilat","hitam birat","hitam bogot","hitam jengat","hitam karbon","hitam kelam","hitam kumbang","hitam kusam","hitam lakan","hitam langit","hitam lebam","hitam lotong","hitam manggis","hitam manis","hitam mata","hitam metalik","hitam pegam","hitam pekat","hitam sabak","hitam selalu","hitam tulang","hitam usam"]', '["ada kambing yang hitam dalam setiap kumpulannya","alang-alang berdawat biarlah hitam","ayam hitam terbang malam","ayam hitam terbang malam, bertali ijuk bertambang tanduk, hinggap di kebun rimbun","batu hitam tak bersanding","hitam bagai pantat belanga","hitam di atas putih","hitam dikatakan putih, putih dikatakan hitam","hitam mata itu mana boleh bercerai dengan putihnya","hitam sebagai kuali","hitam seperti dawat","hitam tahan tempa, putih tahan sesah","hitam, hitam gagak, putih, putih udang kapai (hitam, hitam bendi, putih, putih sadah)","hitam, hitam gula jawa","hitam, hitam tahi minyak dimakan juga, putih-putih ampas kelapa dibuang","hitam-hitam gajah, putih-putih udang kepai","hitam-hitam kereta api, putih-putih kapur sirih","kepala sama hitam (berbulu), pendapat berlain-lain","ketika gagak putih, bangau hitam","kuali mengatakan belanga hitam","kuning oleh kunyit, hitam oleh arang","mati-mati berdawat biar hitam (mati-mati mandi biar basah)","melanggar benang hitam","menanti putih gagak hitam","rambut sama hitam, hati masing-masing","selama gagak hitam, selama air hilir","terpijak benang, arang hitam tampak","terpijak di tanah kapur, putih tapak, terpijak di tanah arang, hitam tapak","undang-undang berbatu hitam"]', '["yang panjang tungkai hitam"]', '[{"peribahasa":"ada kambing yang hitam dalam setiap kumpulannya","makna":"Dalam setiap kelompok atau masyarakat, pasti ada orang yang jahat atau berkelakuan buruk."},{"peribahasa":"alang-alang berdawat biarlah hitam","makna":"Jika mengerjakan sesuatu, janganlah tanggung-tanggung, selesaikan sampai tuntas."},{"peribahasa":"ayam hitam terbang malam","makna":"Sesuatu yang sangat sulit ditemukan atau diketahui."},{"peribahasa":"ayam hitam terbang malam, bertali ijuk bertambang tanduk, hinggap di kebun rimbun","makna":"Sesuatu yang sangat sulit ditemukan atau diketahui."},{"peribahasa":"batu hitam tak bersanding","makna":"Orang yang dianggap tidak ada bandingannya (dalam hal kekuatan, kekuasaan, dan sebagainya)."},{"peribahasa":"hitam bagai pantat belanga","makna":"Sangat hitam."},{"peribahasa":"hitam di atas putih","makna":"Dengan perjanjian atau bukti tertulis yang sah."},{"peribahasa":"hitam dikatakan putih, putih dikatakan hitam","makna":"Berkata bohong; tidak jujur."},{"peribahasa":"hitam mata itu mana boleh bercerai dengan putihnya","makna":"Orang yang sedang berkelahi atau berselisih tidak dapat dipisahkan."},{"peribahasa":"hitam sebagai kuali","makna":"Sangat hitam."},{"peribahasa":"hitam seperti dawat","makna":"Sangat hitam."},{"peribahasa":"hitam tahan tempa, putih tahan sesah","makna":"Orang yang terbukti kebenarannya atau kejujurannya tidak akan takut menghadapi ujian atau cobaan."},{"peribahasa":"hitam, hitam gagak, putih, putih udang kapai (hitam, hitam bendi, putih, putih sadah)","makna":"Setiap orang atau sesuatu memiliki kelebihan dan kekurangannya masing-masing."},{"peribahasa":"hitam, hitam gula jawa","makna":"Meskipun kelihatannya jelek atau tidak menarik, tetapi sebenarnya baik hati atau memiliki kelebihan."},{"peribahasa":"hitam, hitam tahi minyak dimakan juga, putih-putih ampas kelapa dibuang","makna":"Barang yang buruk tetapi berharga disimpan, sedangkan barang yang bagus tetapi tidak berharga dibuang."},{"peribahasa":"hitam-hitam gajah, putih-putih udang kepai","makna":"Setiap orang atau sesuatu memiliki kelebihan dan kekurangannya masing-masing."},{"peribahasa":"hitam-hitam kereta api, putih-putih kapur sirih","makna":"Jangan terkecoh oleh penampilan luar, karena yang kelihatannya buruk belum tentu buruk, dan yang kelihatannya baik belum tentu baik."},{"peribahasa":"kepala sama hitam (berbulu), pendapat berlain-lain","makna":"Setiap orang memiliki pendapat atau pikiran yang berbeda-beda."},{"peribahasa":"ketika gagak putih, bangau hitam","makna":"Sesuatu yang mustahil terjadi."},{"peribahasa":"kuali mengatakan belanga hitam","makna":"Orang yang mencela orang lain, padahal dirinya sendiri lebih buruk."},{"peribahasa":"kuning oleh kunyit, hitam oleh arang","makna":"Mudah terpengaruh oleh lingkungan atau pergaulan."},{"peribahasa":"mati-mati berdawat biar hitam (mati-mati mandi biar basah)","makna":"Jika mengerjakan sesuatu, janganlah tanggung-tanggung, selesaikan sampai tuntas."},{"peribahasa":"melanggar benang hitam","makna":"Melanggar adat atau aturan yang telah ditetapkan."},{"peribahasa":"menanti putih gagak hitam","makna":"Menunggu sesuatu yang tidak mungkin terjadi."},{"peribahasa":"rambut sama hitam, hati masing-masing","makna":"Setiap orang memiliki pendapat atau pikiran yang berbeda-beda."},{"peribahasa":"selama gagak hitam, selama air hilir","makna":"Selama-lamanya; untuk waktu yang tidak terbatas."},{"peribahasa":"terpijak benang, arang hitam tampak","makna":"Kesalahan kecil yang dapat membuka aib yang lebih besar."},{"peribahasa":"terpijak di tanah kapur, putih tapak, terpijak di tanah arang, hitam tapak","makna":"Sifat atau kelakuan seseorang akan dipengaruhi oleh lingkungannya."},{"peribahasa":"undang-undang berbatu hitam","makna":"Hukuman atau aturan yang sangat keras dan tidak dapat diubah lagi."}]');
