","bagai cendawan (tumbuh) di musim hujan","bumi mana yang tak kena hujan","disangka panas sampai petang, kiranya hujan tengah hari","emping terserak hari hujan","hari guruh takkan hujan","hilang kabus, teduh hujan","hinggap bak langau, titik bak hujan","hujan berbalik ke langit","hujan berpohon, panas berasal","hujan emas di negeri orang, hujan batu di negeri sendiri, baik jua di negeri sendiri","hujan jatuh ke pasir","hujan keris lembing di negeri kita, hujan emas perak di negeri orang, baik jua di negeri kita","hujan menimpa bumi","hujan panas permainan hari, senang susah permainan hidup","hujan tak sekali jatuh, simpai tak sekali erat","hujan tempat berteduh, panas tempat berlindung","hujan turun, kambing lari","imam yang adil lebih baik daripada hujan yang lebat","ke mana tumpah hujan dari bubungan, kalau tidak ke cucuran atap","laksana jentayu menantikan hujan","laut mana yang tak berombak, bumi mana yang tak ditimpa hujan","mengharapkan hujan di langit, air di tempayan ditumpahkan","panas setahun dihapuskan oleh hujan sehari","pucuk layu disiram hujan","putih mengandung awan, kelam baja mengandung hujan","sedia payung sebelum hujan","sedikit hujan banyak yang basah","selama hujan, akan panas jua","tak air hujan ditampung","tak lapuk di hujan, tak lekang di panas","tak lekang oleh panas, tak lapuk oleh hujan","tampak gabak di hulu (gabak di hulu tanda akan hujan)","terang kabut, teduh hujan","tidak hujan lagi becek, ini pula hujan"]', '["hujan gol"]', '[{"peribahasa":"ada angin, ada pohonnya (hujan berpohon, panas berasal)","makna":"Setiap kejadian atau peristiwa pasti ada sebab musababnya."},{"peribahasa":"ada hujan ada panas, ada hari boleh balas","makna":"Setiap perbuatan baik atau jahat akan mendapatkan balasannya kelak."},{"peribahasa":"badai reda, hujan pun teduh","makna":"Setelah kesulitan atau perselisihan berakhir, keadaan menjadi tenang kembali."},{"peribahasa":"bagai cendawan (tumbuh) di musim hujan","makna":"Sesuatu yang muncul secara tiba-tiba dan dalam jumlah yang banyak."},{"peribahasa":"bumi mana yang tak kena hujan","makna":"Setiap orang pasti pernah mengalami kesulitan atau kesusahan."},{"peribahasa":"disangka panas sampai petang, kiranya hujan tengah hari","makna":"Sesuatu yang diharapkan baik atau menyenangkan, ternyata berakhir dengan kekecewaan atau kesedihan."},{"peribahasa":"emping terserak hari hujan","makna":"Mengalami nasib sial atau kemalangan."},{"peribahasa":"hari guruh takkan hujan","makna":"Orang yang banyak bicara atau mengancam biasanya tidak akan berbuat apa-apa."},{"peribahasa":"hilang kabus, teduh hujan","makna":"Setelah kesulitan atau kesusahan berlalu, datanglah ketenangan dan kebahagiaan."},{"peribahasa":"hinggap bak langau, titik bak hujan","makna":"Datang secara tiba-tiba dan dalam jumlah yang banyak."},{"peribahasa":"hujan berbalik ke langit","makna":"Sesuatu yang mustahil terjadi."},{"peribahasa":"hujan berpohon, panas berasal","makna":"Setiap kejadian atau peristiwa pasti ada sebab musababnya."},{"peribahasa":"hujan emas di negeri orang, hujan batu di negeri sendiri, baik jua di negeri sendiri","makna":"Meskipun di negeri orang hidup senang dan mewah, lebih baik hidup di negeri sendiri meskipun dalam keadaan sederhana."},{"peribahasa":"hujan jatuh ke pasir","makna":"Kebaikan atau pertolongan yang sia-sia karena tidak dihargai atau tidak dimanfaatkan dengan baik."},{"peribahasa":"hujan keris lembing di negeri kita, hujan emas perak di negeri orang, baik jua di negeri kita","makna":"Meskipun di negeri orang hidup senang dan mewah, lebih baik hidup di negeri sendiri meskipun dalam keadaan sederhana."},{"peribahasa":"hujan menimpa bumi","makna":"Sesuatu yang sudah menjadi takdir atau kodrat alam."},{"peribahasa":"hujan panas permainan hari, senang susah permainan hidup","makna":"Dalam kehidupan, kesenangan dan kesusahan silih berganti, seperti halnya cuaca yang bisa berubah-ubah."},{"peribahasa":"hujan tak sekali jatuh, simpai tak sekali erat","makna":"Suatu pekerjaan atau usaha tidak akan berhasil dengan sekali coba, tetapi harus dilakukan secara bertahap dan terus-menerus."},{"peribahasa":"hujan tempat berteduh, panas tempat berlindung","makna":"Orang yang selalu menjadi tempat meminta pertolongan atau perlindungan."},{"peribahasa":"hujan turun, kambing lari","makna":"Orang yang penakut akan lari tunggang langgang jika menghadapi bahaya."},{"peribahasa":"imam yang adil lebih baik daripada hujan yang lebat","makna":"Pemimpin yang adil dan bijaksana lebih berharga daripada kekayaan yang melimpah."},{"peribahasa":"ke mana tumpah hujan dari bubungan, kalau tidak ke cucuran atap","makna":"Sifat anak tidak akan jauh berbeda dengan sifat orang tuanya."},{"peribahasa":"laksana jentayu menantikan hujan","makna":"Mengharapkan sesuatu dengan penuh harap dan kerinduan."},{"peribahasa":"laut mana yang tak berombak, bumi mana yang tak ditimpa hujan","makna":"Setiap orang pasti pernah mengalami kesulitan atau kesusahan."},{"peribahasa":"mengharapkan hujan di langit, air di tempayan ditumpahkan","makna":"Mengharapkan sesuatu yang belum pasti, tetapi melepaskan sesuatu yang sudah dimiliki."},{"peribahasa":"panas setahun dihapuskan oleh hujan sehari","makna":"Kebaikan yang banyak dapat hilang karena satu kesalahan kecil."},{"peribahasa":"pucuk layu disiram hujan","makna":"Mendapatkan pertolongan atau kebahagiaan di saat yang tepat."},{"peribahasa":"putih mengandung awan, kelam baja mengandung hujan","makna":"Dari tanda-tanda atau gejala yang ada, dapat diketahui apa yang akan terjadi."},{"peribahasa":"sedia payung sebelum hujan","makna":"Bersiap-siap sebelum terjadi sesuatu yang tidak diinginkan."},{"peribahasa":"sedikit hujan banyak yang basah","makna":"Kesalahan kecil yang dapat menimbulkan kerugian besar."},{"peribahasa":"selama hujan, akan panas jua","makna":"Setelah mengalami kesusahan, pasti akan datang kebahagiaan."},{"peribahasa":"tak air hujan ditampung","makna":"Tidak mau menerima pemberian atau pertolongan orang lain."},{"peribahasa":"tak lapuk di hujan, tak lekang di panas","makna":"Sesuatu yang kuat dan tahan lama; adat atau tradisi yang tidak berubah oleh zaman."},{"peribahasa":"tak lekang oleh panas, tak lapuk oleh hujan","makna":"Sesuatu yang kuat dan tahan lama; adat atau tradisi yang tidak berubah oleh zaman."},{"peribahasa":"tampak gabak di hulu (gabak di hulu tanda akan hujan)","makna":"Dari tanda-tanda atau gejala yang ada, dapat diketahui apa yang akan terjadi."},{"peribahasa":"terang kabut, teduh hujan","makna":"Setelah kesulitan atau kesusahan berlalu, datanglah ketenangan dan kebahagiaan."},{"peribahasa":"tidak hujan lagi becek, ini pula hujan","makna":"Sudah susah, bertambah susah lagi."}]');
